"use strict";(self.webpackChunkbcsd_blog=self.webpackChunkbcsd_blog||[]).push([[7307],{9263:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"/guide-2","metadata":{"permalink":"/guideline/guide-2","source":"@site/@guideline/guide-2.mdx","title":"VSCode \uae30\ubc18 \uc5c5\ub85c\ub4dc \ubc29\ubc95","description":"VSCode \uae30\ubc18 \uc5c5\ub85c\ub4dc \ubc29\ubc95","date":"2024-08-14T00:00:00.000Z","tags":[{"label":"\uac00\uc774\ub4dc","permalink":"/guideline/tags/\uac00\uc774\ub4dc"},{"label":"\uc5c5\ub85c\ub4dc \ubc29\ubc95","permalink":"/guideline/tags/\uc5c5\ub85c\ub4dc-\ubc29\ubc95"}],"readingTime":4.36,"hasTruncateMarker":true,"authors":[{"name":"Daeeui Kim","url":"https://github.com/kimeodml","email":"kimeodml@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/88065770?v=4","key":"kimeodml"}],"frontMatter":{"date":"2024-08-14T00:00:00.000Z","authors":"kimeodml","title":"VSCode \uae30\ubc18 \uc5c5\ub85c\ub4dc \ubc29\ubc95","description":"VSCode \uae30\ubc18 \uc5c5\ub85c\ub4dc \ubc29\ubc95","keywords":["\uac00\uc774\ub4dc","\uc5c5\ub85c\ub4dc \ubc29\ubc95"],"tags":["\uac00\uc774\ub4dc","\uc5c5\ub85c\ub4dc \ubc29\ubc95"]},"unlisted":false,"nextItem":{"title":"github\uc5d0\uc11c \uc5c5\ub85c\ub4dc\ud558\ub294 \ubc29\ubc95","permalink":"/guideline/guide-1"}},"content":"\ub9ac\uc561\ud2b8\ub97c \uae30\ubc18\uc73c\ub85c \ud55c \ud504\ub85c\uc81d\ud2b8\uc774\uae30 \ub54c\ubb38\uc5d0 **VSCode**\ub97c \uad8c\uc7a5\ud569\ub2c8\ub2e4.\\n\\n\uc791\uc131\ud55c \uae00\uc758 \uacb0\uacfc\ubb3c\uc744 \ub85c\uceec \ud658\uacbd\uc5d0\uc11c \ud655\uc778\ud558\uace0 \uc2f6\uc740 \ubd84\ub4e4\uc740 \ucc38\uace0 \ubc14\ub78d\ub2c8\ub2e4.\\n\\n{/* truncate */}\\n\\n## VSCode\uc5d0\uc11c Git \uc5f0\ub3d9\ud558\uae30\\n\\n\ud574\ub2f9 [\ub9c1\ud06c](https://velog.io/@ahnsanghyeon/VSCode%EC%97%90%EC%84%9C-Git-%EC%97%B0%EB%8F%99%ED%95%98%EA%B8%B0)\ub97c \ucc38\uace0\ud558 Git \uc5f0\ub3d9\uc744 \uc9c4\ud589\ud574 \uc90d\ub2c8\ub2e4.\\n\\n## \ube14\ub85c\uadf8 \uc2e4\ud589\ud558\uae30\\n\\n[repo](https://github.com/BCSDLab/BCSD_BLOG) \ub9c1\ud06c\ub97c \ub4e4\uc5b4\uac00\uc2dc\uba74 \ud604\uc7ac \ud2b8\ub799\ubcc4\ub85c \ubd84\ub958\ud574 \ub193\uc740 \uac83\uc744 \ubcf4\uc2e4 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@guideline/guide-2/Untitled.png\\" />\\n\\n**Code** \ubc84\ud2bc\uc744 \ub204\ub974\uba74 \ud574\ub2f9 repo\uc758 \uae43\ud5d9 \ub9c1\ud06c\ub97c \ud655\uc778\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \\n\\n\uc544\ub798\uc758 \ub9c1\ud06c\ub97c \ubcf5\uc0ac\ud55c \ud6c4\uc5d0 \uc6d0\ud558\ub294 \ud3f4\ub354 \uc704\uce58\uc5d0 \uc544\ub798\uc758 \uba85\ub839\ubb38\uc744 \uc785\ub825\ud558\uba74 \ud574\ub2f9 repo\uac00 \ubcf5\uc0ac\ub429\ub2c8\ub2e4.\\n\\n```jsx\\ngit clone https://github.com/BCSDLab/BCSD_BLOG\\n```\\n\\n<br />\\n\\n\ud504\ub85c\uc81d\ud2b8\ub97c \uc2e4\ud589\ud558\uae30 \uc704\ud574\uc11c \ud328\ud0a4\uc9c0 \ud234\uc774 \ud544\uc694\ud569\ub2c8\ub2e4. \uc544\ub798\uc758 \uba85\ub839\ubb38\uc744 \ud130\ubbf8\ub110\uc5d0 \uc2e4\ud589\ud558\uba74 \ud504\ub85c\uc81d\ud2b8\uac00 \uc2e4\ud589\ub429\ub2c8\ub2e4!\\n\\n```jsx\\nnpm install\\n\\nnpm start \\n```\\n<br/>\\n\\n\uc544\ub798\uc640 \uac19\uc774 [`http://localhost:3000/`](http://localhost:3000/) \uc5d0\uc11c \ud655\uc778\ud558\uc2e4 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc774\uc81c \uae00\uc744 \uc791\uc131\ud558\uba74\uc11c \uc2e4\uc2dc\uac04\uc73c\ub85c \ud655\uc778\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n<img src=\\"/img/@guideline/guide-2/Untitled 1.png\\" />\\n\\n\\n## \ube0c\ub79c\uce58 \uc0dd\uc131\\n\\n\uc6b0\uc120 git-flow\ub97c \ud55c \ub208\uc5d0 \ubcfc \uc218 \uc788\ub294 \ud655\uc7a5\uc790 `git-graph`\ub97c \ub2e4\uc6b4\ubc1b\ub294 \uac83\uc744 \ucd94\ucc9c\ud569\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@guideline/guide-2/Untitled 2.png\\" style={{ marginBottom: \\"30px\\" }}/>\\n\\n`git-graph` \ubc84\ud2bc\uc744 \ub204\ub974\uba74 \ud604\uc7ac `main` \ube0c\ub79c\uce58\uc5d0 \uc704\uce58\uc5d0 \uc788\ub294 \uac83\uc744 \ud655\uc778\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@guideline/guide-2/Untitled 3.png\\" style={{ marginBottom: \\"30px\\" }}/>\\n\\n\ud130\ubbf8\ub110\uc5d0 \uc544\ub798\uc758 \uba85\ub839\ubb38\uc744 \uc791\uc131\ud558\uba74 `main`\uc5d0\uc11c \uc0c8\ub86d\uac8c \uc0dd\uc131\ud55c \ube0c\ub79c\uce58\ub85c \ud604\uc7ac \uc704\uce58\uac00 \uc774\ub3d9\ud569\ub2c8\ub2e4.\\n\uc774\ub54c \ube0c\ub79c\uce58\uba85\uc758 \uacbd\uc6b0 `[\uae43\ud5d9 \uc544\uc774\ub514] :[mdx \ud30c\uc77c\uba85]`\uc73c\ub85c \uc124\uc815\ud574 \uc8fc\uc138\uc694.\\n\\n```jsx\\ngit checkout -b \ube0c\ub79c\uce58 \uc774\ub984\\n\\nex) git checkout -b example/guideline\\n```\\n\\n<br />\\n\\n`git-graph`\ub97c \ud655\uc778\ud574 \ubcf4\uba74 \uc0c8\ub86d\uac8c \uc0dd\uc131\ub41c \ube0c\ub79c\uce58\ub85c \ud604\uc7ac \uc704\uce58\uac00 \uc774\ub3d9\ud55c \uac83\uc744 \ud655\uc778\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@guideline/guide-2/Untitled 4.png\\" />\\n\\n\\n\\n## \uae00 \uc791\uc131\\n\\nNotion\uc5d0\uc11c \uc791\uc131\ud55c \ud6c4 export\ud574\uc11c \uae00\uc744 \ubcf5\uc0ac/\ubd99\uc5ec \ub123\uae30 \ud558\uac70\ub098 \uc9c1\uc811 mdx \ud30c\uc77c\uc5d0\uc11c \uc791\uc131\ud558\uba74 \ub429\ub2c8\ub2e4. \ud574\ub2f9 [\ud15c\ud50c\ub9bf \uc0ac\uc6a9 \uac00\uc774\ub4dc](https://blog.bcsdlab.com/guideline/template)\ub97c \ucc38\uace0\ud558\uc5ec \ud544\uc218\uc801\uc73c\ub85c \ub4e4\uc5b4\uac00\uc57c \ud560 \ube14\ub85c\uae45 \uc815\ubcf4\ub97c \uaf2d \uae30\uc7ac\ud55c \ud6c4\uc5d0 \uc791\uc131\ud558\uae30\ub97c \ubc14\ub78d\ub2c8\ub2e4.\\n\\n- [\uc774\ubbf8\uc9c0](https://blog.bcsdlab.com/guideline/template#%EC%82%AC%EC%A7%84-%EC%82%AC%EC%9A%A9-%EC%98%88%EC%8B%9C)\uc640 [\ube44\ub514\uc624](https://blog.bcsdlab.com/guideline/template#%EB%B9%84%EB%94%94%EC%98%A4-%EC%82%AC%EC%9A%A9-%EC%98%88%EC%8B%9C)\ub294 \ud574\ub2f9 \ub9c1\ud06c\ub97c \ucc38\uace0 \ubd80\ud0c1\ub4dc\ub9bd\ub2c8\ub2e4.\\n\\n## \uc5c5\ub85c\ub4dc \ubc29\uc2dd\\n\\n\\n*\uc791\uc131\uc790\uc758 \ud2b8\ub799\uc5d0 \ub9de\uac8c* \ud30c\uc77c\uc744 \uc0dd\uc131\ud55c \ud6c4\uc5d0 \uc791\uc131\ud574 \uc8fc\uc2dc\uba74 \ub429\ub2c8\ub2e4. **\ud30c\uc77c\uba85\uc758 \uacbd\uc6b0 \ube0c\ub79c\uce58\uba85\uacfc \ub3d9\uc77c\ud558\uac8c \uc9c4\ud589\ud574 \uc8fc\uc138\uc694.** \\n\\n- ex) \uae43\ud5d9 \uc544\uc774\ub514\uac00 `example`\uc774\uace0 \ud30c\uc77c\uba85\uc774 `guideline.mdx` \ub77c\uba74 \ube0c\ub79c\uce58\uba85\uc740 `example/guideline`\\n\\n\ubcc0\uacbd\ub41c \uc0ac\ud56d\uc744 **\uc2a4\ud14c\uc774\uc9d5\ub41c \ubcc0\uacbd \uc0ac\ud56d**\uc73c\ub85c \uc62c\ub9b0 \ud6c4 `commit` \ud55c \ud6c4 `push`\ub97c \ud558\uba74  VSCode\uc5d0\uc11c\uc758 \uc791\uc5c5\uc740 \ub05d\ub0ac\uc2b5\ub2c8\ub2e4!\\n\\n\uc544\ub798\uc758 \uba85\ub839\ubb38\uc744 \uc21c\uc11c\ub300\ub85c \uc791\uc131\ud558\uba74 \ub429\ub2c8\ub2e4.\\n\\n```jsx \\n\\ngit add -A\\n\\ngit commit -m \\"docs: \ucee4\ubc0b \uc608\uc81c\uc785\ub2c8\ub2e4.\\"\\n\\ngit push\\n\\n```\\n\\n\ub9cc\uc57d \uba85\ub839\ubb38\uc774 \ud5f7\uac08\ub9b0\ub2e4\uba74 \uc544\ub798\uc758 \uc774\ubbf8\uc9c0\ucc98\ub7fc GUI\ub97c \ud1b5\ud574 \uc9c4\ud589\ud558\uba74 \ub429\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@guideline/guide-2/Untitled 5.png\\" style={{ marginBottom: \\"50px\\" }}/>\\n\\n\\n## pr \ub0a0\ub9ac\uae30\\n\\npr \ub0a0\ub9ac\ub294 \ubc29\uc2dd\uc740 github\uc5d0\uc11c \uc5c5\ub85c\ub4dc\ud558\ub294 \ubc29\ubc95\uc758 [Pull Request \ub0a0\ub9ac\uae30](http://localhost:3000/guideline/guide-1#pull-request-%EB%82%A0%EB%A6%AC%EA%B8%B0)\uc640 \ub3d9\uc77c\ud569\ub2c8\ub2e4.\\n\\n<br />\\n<br />\\n\\n*\uc704\uc758 \ud504\ub85c\uc138\uc2a4\uac00 \uc5b4\ub835\ub2e4\uba74 \ub178\uc158\uc5d0 \uc791\uc131\ud55c \uae00\uc744 markdown \ud615\uc2dd\uc73c\ub85c \ub0b4\ubcf4\ub0b4\uae30\ud55c \ud6c4\uc5d0 **#bcsd_blog_\ubb38\uc758**\uc5d0 \uc694\uccad\ud558\uba74 \uc9c4\ud589\ud558\ub3c4\ub85d \ud558\uaca0\uc2b5\ub2c8\ub2e4.*"},{"id":"/guide-1","metadata":{"permalink":"/guideline/guide-1","source":"@site/@guideline/guide-1.mdx","title":"github\uc5d0\uc11c \uc5c5\ub85c\ub4dc\ud558\ub294 \ubc29\ubc95","description":"github\uc5d0\uc11c \ubc14\ub85c \uc774\uc6a9\ud558\ub294 \ubc29\ubc95","date":"2024-08-13T00:00:00.000Z","tags":[{"label":"\uac00\uc774\ub4dc","permalink":"/guideline/tags/\uac00\uc774\ub4dc"},{"label":"\uc5c5\ub85c\ub4dc \ubc29\ubc95","permalink":"/guideline/tags/\uc5c5\ub85c\ub4dc-\ubc29\ubc95"}],"readingTime":5.395,"hasTruncateMarker":true,"authors":[{"name":"Daeeui Kim","url":"https://github.com/kimeodml","email":"kimeodml@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/88065770?v=4","key":"kimeodml"}],"frontMatter":{"date":"2024-08-13T00:00:00.000Z","authors":"kimeodml","title":"github\uc5d0\uc11c \uc5c5\ub85c\ub4dc\ud558\ub294 \ubc29\ubc95","description":"github\uc5d0\uc11c \ubc14\ub85c \uc774\uc6a9\ud558\ub294 \ubc29\ubc95","keywords":["\uac00\uc774\ub4dc","\uc5c5\ub85c\ub4dc \ubc29\ubc95"],"tags":["\uac00\uc774\ub4dc","\uc5c5\ub85c\ub4dc \ubc29\ubc95"]},"unlisted":false,"prevItem":{"title":"VSCode \uae30\ubc18 \uc5c5\ub85c\ub4dc \ubc29\ubc95","permalink":"/guideline/guide-2"},"nextItem":{"title":"BCSD \ube14\ub85c\uadf8\uc758 \ubc29\ud5a5\uc131","permalink":"/guideline/blog-direction"}},"content":"github\uc5d0\uc11c \ubc14\ub85c \uae00\uc744 \uc5c5\ub85c\ub4dc \ud558\ub294 \ubc29\uc2dd\uc785\ub2c8\ub2e4.\\n\\n{/* truncate */}\\n\\n- \uc7a5\uc810\\n    - \uc27d\uace0, \uac04\ud3b8\ud568 / \ube60\ub984\\n    - preview\ub97c \ud1b5\ud574 \ubbf8\ub9ac \ubcf4\uae30 \uac00\ub2a5\\n- \ub2e8\uc810\\n    - \uc774\ubbf8\uc9c0 \ubc0f \ube44\ub514\uc624 \ud30c\uc77c \ucd94\uac00 \uc2dc \ud3f4\ub354 \uc774\ub3d9 \ud544\uc694\\n    - \ud55c \ubc88\uc5d0 \ucd94\uac00 \ubd88\uac00\ub2a5\\n    - preview \uae30\ub2a5\uc774 \uc788\uc5b4\ub3c4 \ube14\ub85c\uadf8\uc5d0 \ubcf4\uc5ec\uc9c0\ub294 \uac83\uacfc \ucc28\uc774\uac00 \uc788\uc74c\\n\\n\ub9cc\uc57d \uc704\uc758 \ub2e8\uc810\uc73c\ub85c github\uc5d0 \ubc14\ub85c \uc791\uc131\ud558\ub294 \ubc29\uc2dd\uc774 \uc5b4\ub824\uc6b4 \uacbd\uc6b0 \ud574\ub2f9 [\uac00\uc774\ub4dc](/guideline/guide-2)\ub97c \uc77d\uc5b4\uc8fc\uc138\uc694.\\n\\n## \ub178\uc158\uc5d0 \uae00 \uc791\uc131\\n\\n\ub9c8\ud06c\ub2e4\uc6b4 \ubb38\ubc95\uc744 \uc5b4\ub824\uc6cc\ud558\uc2e4 \uacbd\uc6b0 \ub178\uc158\uc5d0 \uba3c\uc800 \uae00\uc744 \uc791\uc131\ud574 \uc8fc\uc138\uc694. \ub0b4\ubcf4\ub0b4\uae30 \uc2dc **Markerdown**\uc73c\ub85c \ub0b4\ubcf4\ub0b4 \uc8fc\uc138\uc694. \uadf8\ub7fc \uc790\ub3d9\uc73c\ub85c \ub9c8\ud06c\ub2e4\uc6b4 \ud615\uc2dd\uc73c\ub85c \ubcc0\ud658\ub429\ub2c8\ub2e4.\\n\\n<p align=\\"center\\">\\n  <img src=\\"/img/@guideline/guide-1/Untitled.png\\" />\\n</p>\\n\\n## BCSDLab \ub808\ud3ec\ub85c \uc774\ub3d9\\n\\n[bcsd \ube14\ub85c\uadf8 repo](https://github.com/BCSDLab/BCSD_BLOG)\ub85c \uc774\ub3d9\ud569\ub2c8\ub2e4. \uadf8\ub7fc \uc544\ub798\uc640 \uac19\uc774 \ub2e4\uc591\ud55c \ud3f4\ub354 \uacbd\ub85c\ub97c \ud655\uc778\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \\n\\n\uba3c\uc800 `main` \ubc84\ud2bc\uc744 \ub20c\ub7ec \uc790\uc2e0\uc758 \ube0c\ub79c\uce58\ub97c \ub9cc\ub4ed\ub2c8\ub2e4. \ube0c\ub79c\uce58\uba85\uc758 \uacbd\uc6b0 `[\uae43\ud5d9 \uc544\uc774\ub514]/[mdx \ud30c\uc77c\uba85]`\ub85c \uc9c0\uc815\ud574 \uc8fc\uc138\uc694.\\n\\n<p align=\\"center\\">\\n  <img src=\\"/img/@guideline/guide-1/Untitled 1.png\\" />\\n</p>\\n\\n\\n\ube0c\ub79c\uce58\ub97c \uc0dd\uc131\ud558\uba74 \uc790\uc2e0\uc774 \uc0dd\uc131\ud55c \ube0c\ub79c\uce58\ub85c \uc774\ub3d9\ud55c \ud6c4\uc5d0 \uae00 \uc791\uc131, \uc774\ubbf8\uc9c0 \uc5c5\ub85c\ub4dc \ub4f1\uc758 \ub2e4\uc591\ud55c \uc791\uc5c5\uc744 \uc9c4\ud589\ud558\uba74 \ub429\ub2c8\ub2e4.\\n\\n\uc544\ub798\uc758 \uc774\ubbf8\uc9c0\ucc98\ub7fc \uc0c8\ub86d\uac8c \uc0dd\uc131\ud55c \ube0c\ub79c\uce58\uba85\uc73c\ub85c \ubcc0\uacbd\ub418\uc5c8\ub2e4\uba74 \ud604\uc7ac \uc704\uce58\uac00 \uc790\uc2e0\uc774 \uc0dd\uc131\ud55c \ube0c\ub79c\uce58\ub77c\ub294 \uac83\uc785\ub2c8\ub2e4.\\n\\n<p>\\n  <img src=\\"/img/@guideline/guide-1/Untitled 2.png\\" />\\n</p>\\n\\n\\n\\n\\n\\n## \uc774\ubbf8\uc9c0 \ubc0f \ube44\ub514\uc624 \ud30c\uc77c \uc5c5\ub85c\ub4dc\\n\\n\uc774\ubbf8\uc9c0 \ubc0f \ube44\ub514\uc624 \ud30c\uc77c\uc744 \uc0ac\uc6a9\ud558\uae30 \uc704\ud574\uc11c\ub294 \uac01\uac01\uc758 github\uc5d0 \uc5c5\ub85c\ub4dc\ud55c \ud6c4\uc5d0 \uacbd\ub85c\ub97c \uc791\uc131\ud574\uc57c \ud569\ub2c8\ub2e4.\\n\\n**\uc774\ubbf8\uc9c0**\uc758 \uacbd\uc6b0 `/img/@\ud2b8\ub799` \uc5d0 **\ube44\ub514\uc624**\ub294 \uc6d0\ud558\ub294 \uacbd\ub85c\uc5d0 \uc800\uc7a5\ud569\ub2c8\ub2e4. \ub418\ub3c4\ub85d\uc774\uba74 \uc4f0\ub294 \uae00\uc5d0 \uac00\uae5d\uac8c \ub450\uac70\ub098 \uac01 \ud2b8\ub799 \ud3f4\ub354\uc5d0 \ub9cc\ub4e4\uc5b4\uc838 \uc788\ub294 video \ud3f4\ub354\ub97c \uc0ac\uc6a9\ud558\ub294 \uac83\uc744 \ucd94\ucc9c\ud569\ub2c8\ub2e4. \\n\\n\uc544\ub798\uc640 \uac19\uc774 `/img/@guideline`\uc5d0 \uc774\ubbf8\uc9c0\ub97c \uc5c5\ub85c\ub4dc\ud558\uba74 \ub429\ub2c8\ub2e4. \ucee4\ubc0b\uba85\uc758 \uacbd\uc6b0 `docs: [\uc790\uc720\ub86d\uac8c]` \uc9c0\uc815\ud558\uba74 \ub429\ub2c8\ub2e4.\\n\\n<p align=\\"center\\">\\n  <img src=\\"/img/@guideline/guide-1/Untitled 3.png\\" />\\n</p>\\n\\n\ud558\ub2e8\uc758 `Commit changes` \ubc84\ud2bc\uc744 \ub204\ub974\uba74 \ucee4\ubc0b\uc774 \uc791\uc131\ub429\ub2c8\ub2e4. \uc774\ub54c \ucee4\ubc0b\uc774 \uc62c\ubc14\ub978 \ube0c\ub79c\uce58(ex. `kimeodml/guideline`)\uc5d0 \uc704\uce58\ud574 \uc788\ub294\uc9c0 \ud655\uc778\ud574 \uc8fc\uc138\uc694. \\n\\n## \uae00 \uc791\uc131 \ubc0f \uc62c\ub9ac\uae30\\n\\n\uc774 \uae00\uc740 \uac00\uc774\ub4dc\ub77c\uc778\uc5d0 \uc791\uc131\ud560 \uae00\uc774\uae30 \ub54c\ubb38\uc5d0 `@guideline`\uc73c\ub85c \uc774\ub3d9\ud588\uc2b5\ub2c8\ub2e4. **create new file** \ubc84\ud2bc\uc744 \ub20c\ub7ec \uc0c8\ub86d\uac8c \ud30c\uc77c\uc744 \uc0dd\uc131\ud569\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@guideline/guide-1/Untitled 4.png\\" />\\n\\n[\ud15c\ud50c\ub9bf \uc0ac\uc6a9 \uac00\uc774\ub4dc](https://blog.bcsdlab.com/guideline/template)\uc5d0 \ub9de\uac8c \ube14\ub85c\uae45 \uc815\ubcf4\ub97c \uae30\uc785\ud569\ub2c8\ub2e4. \uc774 \ud6c4 \uc9c1\uc811 \uae00\uc744 \ub9c8\ud06c\ub2e4\uc6b4 \ud615\uc2dd\uc73c\ub85c \uc791\uc131\ud558\uac70\ub098 \ub178\uc158\uc5d0\uc11c \ub0b4\ubcf4\ub0b4\uae30\ud55c \ud30c\uc77c\uc744 \ubcf5\uc0ac/\ubd99\uc5ec\ub123\uae30 \ud569\ub2c8\ub2e4.\\n\\n\uc774\ubbf8\uc9c0\uac00 \uc788\uc744 \uacbd\uc6b0 \ubbf8\ub9ac \uc5c5\ub85c\ub4dc\ud55c \uc774\ubbf8\uc9c0 \uacbd\ub85c\ub85c \uc218\uc815\ud569\ub2c8\ub2e4.\\n\\n```jsx\\n// Before\\n![Untitled](github%E1%84%8B%E1%85%A6%E1%84%89%E1%85%A5%20%E1%/Untitled.png)\\n\\n\\n// After\\n<img src=\\"/img/@guideline/Untitled.png\\" />\\n```\\n\\n**\ube0c\ub79c\uce58\uba85**(ex. `kimeodml/guideline`)\uacfc **\ud30c\uc77c\uba85**(ex. `guideline.mdx`)\uc744 \ub3d9\uc77c\ud558\uac8c \uc124\uc815\ud574 \uc8fc\uc138\uc694.\\n\\n<p align=\\"center\\">\\n  <img src=\\"/img/@guideline/guide-1/Untitled 5.png\\" />\\n</p>\\n\\n`Commit changes`\ub97c \ub204\ub974\uba74 \uc791\uc131\ub41c \ud30c\uc77c\uc774 github\uc5d0 \uc5c5\ub85c\ub4dc\ub429\ub2c8\ub2e4!!\\n\\n\\n## Pull Request \ub0a0\ub9ac\uae30\\n\\n\uc774\uc81c \uc0c8\ub86d\uac8c \uc0dd\uc131\ub41c \ube0c\ub79c\uce58\uc5d0\uc11c `main` \ube0c\ub79c\uce58\ub85c \ubcd1\ud569\ud558\uae30 \uc704\ud574\uc11c\ub294 [pull-request](https://docs.github.com/ko/pull-requests)\ub97c \ub0a0\ub824\uc57c \ud569\ub2c8\ub2e4.\\n\\n\uba54\uc778 \ud398\uc774\uc9c0\ub85c \ub3cc\uc544\uc624\uba74 \ub178\ub780 \ucc3d\uc774 \ub744\uc6cc\uc838 \uc788\ub294 \uac83\uc744 \ud655\uc778\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc5ec\uae30\uc11c `Compare & pull-request` \ubc84\ud2bc\uc744 \ub204\ub974\uba74 pr \ucc3d\uc73c\ub85c \ub118\uc5b4\uac00\uc9d1\ub2c8\ub2e4.\\n\\n<p align=\\"center\\">\\n  <img src=\\"/img/@guideline/guide-1/Untitled 6.png\\" />\\n</p>\\n\\npr \uc81c\ubaa9\uc740 `[\ud2b8\ub799\uba85]: [\uc790\uc720\ub86d\uac8c]`\ub85c \uc791\uc131\ud558\uace0, \uc120\ud0dd \uc0ac\ud56d\uc73c\ub85c \uae00\uc744 \uc694\uc57d\ud560 \uc218 \uc788\uac8c \ud15c\ud50c\ub9bf\uc744 \uc0dd\uc131\ud574 \ub193\uc558\uc2b5\ub2c8\ub2e4. \uc790\uc720\ub86d\uac8c \uc801\uac70\ub098 \uc0dd\ub7b5\ud574\ub3c4 \ub429\ub2c8\ub2e4.\\n\\n- \uc774\ub54c \ubcd1\ud569\ub418\ub294 \ubc29\ud5a5\uc774 `main` \ube0c\ub79c\uce58\uc778\uc9c0 \ud655\uc778\ud574 \uc8fc\uc138\uc694!\\n\\n<p align=\\"center\\">\\n  <img src=\\"/img/@guideline/guide-1/Untitled 7.png\\" />\\n</p>\\n\\n\uc774\uc81c `Create pull request` \ubc84\ud2bc\uc744 \ub204\ub974\uba74 bcsdlab \uc2ac\ub799 \ucc44\ub110\uc758 **#bcsd_blog_\ubb38\uc758**\ub85c \uc54c\ub9bc\uc774 \uac00\uc9d1\ub2c8\ub2e4. \ub3d9\uc544\ub9ac\uc6d0\uc774 pr\uc744 \ud655\uc778\ud55c \ud6c4\uc5d0 \ubcd1\ud569\ub418\uba74 \uc790\ub3d9\uc73c\ub85c \ubc30\ud3ec\ub429\ub2c8\ub2e4.\\n\\n\ud558\uc9c0\ub9cc \ub098\ub294 \ube14\ub85c\uadf8\ub97c \ub0b4 \ucef4\ud4e8\ud130\uc5d0 \uc2e4\ud589\ud558\uba74\uc11c \uae00\uc744 \uc4f0\uace0 \uc2f6\ub2e4! \ud558\uc2dc\ub294 \ubd84\uc740 [\ub2e4\uc74c \uac00\uc774\ub4dc](/guideline/guide-2)\ub97c \ucc38\uace0\ud574 \uc8fc\uc138\uc694."},{"id":"/blog-direction","metadata":{"permalink":"/guideline/blog-direction","source":"@site/@guideline/blog-direction.mdx","title":"BCSD \ube14\ub85c\uadf8\uc758 \ubc29\ud5a5\uc131","description":"BCSD \ube14\ub85c\uadf8\uc5d0 \uc624\uc2e0 \uac83\uc744 \ud658\uc601\ud574\uc694! \uc5ec\ub7ec\ubd84\uc774 \uc774 \uacf5\uac04\uc744 \uc5b4\ub5bb\uac8c \ud65c\uc6a9\ud560 \uc218 \uc788\ub294\uc9c0 \uc54c\ub824\ub4dc\ub9b4\uac8c\uc694.","date":"2024-03-24T00:00:00.000Z","tags":[],"readingTime":5.315,"hasTruncateMarker":true,"authors":[{"name":"Haesung Jung","url":"https://github.com/junghaesung79","email":"gotjd0230@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/96577250?v=4","key":"junghaesung79"}],"frontMatter":{"date":"2024-03-24T00:00:00.000Z","authors":"junghaesung79","title":"BCSD \ube14\ub85c\uadf8\uc758 \ubc29\ud5a5\uc131","description":"BCSD \ube14\ub85c\uadf8\uc5d0 \uc624\uc2e0 \uac83\uc744 \ud658\uc601\ud574\uc694! \uc5ec\ub7ec\ubd84\uc774 \uc774 \uacf5\uac04\uc744 \uc5b4\ub5bb\uac8c \ud65c\uc6a9\ud560 \uc218 \uc788\ub294\uc9c0 \uc54c\ub824\ub4dc\ub9b4\uac8c\uc694.","keywords":["\uccab","\ube14\ub85c\uae45","\uc2dc\uc791","\ubc29\ud5a5"]},"unlisted":false,"prevItem":{"title":"github\uc5d0\uc11c \uc5c5\ub85c\ub4dc\ud558\ub294 \ubc29\ubc95","permalink":"/guideline/guide-1"},"nextItem":{"title":"\ud15c\ud50c\ub9bf \uc0ac\uc6a9 \uac00\uc774\ub4dc","permalink":"/guideline/template"}},"content":"BCSDLab \ube14\ub85c\uadf8\uac00 \ucd94\uad6c\ud558\ub294 \ubc29\ud5a5\uacfc \uc774 \uacf5\uac04\uc774 \uc5b4\ub5a4 \ubaa8\uc2b5\uc774 \ub418\uc5b4\uac08 \uc9c0\uc5d0 \ub300\ud574\uc11c \ub9d0\uc500\ub4dc\ub9b4\uac8c\uc694\\n\\n{/* truncate */}\\n\\n\uc548\ub155\ud558\uc138\uc694! \uc800\ub294 FE \ud2b8\ub799 \ub808\uade4\ub7ec \uc815\ud574\uc131\uc785\ub2c8\ub2e4! \ucd5c\uadfc\uc5d0 \uc800\ud76c FE \ud2b8\ub799\uc5d0\uc11c \uc0c8\ub85c\uc6b4 \ud65c\ub3d9\uc744 \uc2dc\uc791\ud588\uc5b4\uc694. \ub2e4\uc591\ud55c \uc18c\uadf8\ub8f9 \ud65c\ub3d9\uc774 \uc788\uc5c8\ub294\ub370, \uadf8\uc911 \uc800\ub294 \ud2b8\ub7ec\ube14 \uc288\ud305\uc774\ub098 \ud559\uc2b5 \uacbd\ud5d8\uc5d0 \uad00\ud574\uc11c \ube14\ub85c\uadf8\ub97c \uc368\ubcf4\ub294 \uadf8\ub8f9\uc5d0\uc11c \ud65c\ub3d9\ud558\uac8c \ub410\uc5b4\uc694. \uadf8\ub807\uac8c \ud574\uc11c \uac1c\uc124\ub41c \uac8c \ubc14\ub85c BCSDLab\uc758 \uc804\uc6a9 \ube14\ub85c\uadf8 \ud398\uc774\uc9c0\uc785\ub2c8\ub2e4! \uc624\ub298\uc740 \uac04\ub2e8\ud788 BCSDLab \ube14\ub85c\uadf8\uac00 \ucd94\uad6c\ud558\ub294 \ubc29\ud5a5\uacfc \uc774 \uacf5\uac04\uc774 \uc5b4\ub5a4 \ubaa8\uc2b5\uc774 \ub418\uc5b4\uac08 \uc9c0\uc5d0 \ub300\ud574\uc11c \ub9d0\uc500\ub4dc\ub9b4\uac8c\uc694.\\n\\n<div style={{ display: \\"flex\\", flexDirection: \\"column\\", width: \\"50%\\", margin: \\"50px auto\\" }}>\\n  <img src=\\"/img/@guideline/blog-direction/img1.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ display: \\"flex\\", justifyContent: \\"center\\" }} />\\n</div>\\n\\n\uc18c\uadf8\ub8f9\uc774 \uc0dd\uae30\uace0 \ucd08\uae30\uc5d0 \ube14\ub85c\uadf8\uc5d0 \uc5b4\ub5a4 \uac83\uc744 \uc368\uc57c \ud560\uc9c0 \uace0\ubbfc\ub9cc \ud558\uba74\uc11c \uc2dc\uac04\uc774 \uc9c0\ub098\uac00\ub358 \uc911\uc5d0 \ube14\ub85c\uadf8 \uacbd\ud5d8\uc774 \ud48d\ubd80\ud558\uc2e0 BCSD \ud68c\uc7a5\ub2d8\uaed8\uc11c \uba87 \ub9c8\ub514 \ud574\uc8fc\uc168\uc5b4\uc694. \uadf8\ub54c \ub4e4\uc5c8\ub358 \uc870\uc5b8\uacfc \uc81c \uc0dd\uac01\uc744 \uc11e\uc5b4\uc11c \ub9d0\uc500\ub4dc\ub9b4\uac8c\uc694.\\n\\n\uc5ec\ub7ec \uae30\uc220 \uacf5\ubd80\ub97c \ud558\uba74\uc11c \uc774\ub97c \uae30\ub85d\ud558\uace0 \uc2f6\uac70\ub098 \uc544\ub2c8\uba74 \ub2e8\uc21c\ud788 \ud558\uba74 \uc88b\ub2e4\uace0 \ud574\uc11c \ube14\ub85c\uadf8\ub97c \uc2dc\ub3c4\ud558\ub824 \ud558\ub294 \uc0ac\ub78c\uc774 \ub9ce\uc774 \uc788\uc744 \uac70\uc608\uc694. \ud558\uc9c0\ub9cc \uc0dd\uac01\ub9cc \ud558\uace0 \uc2dc\uc791\ud558\uc9c0 \ubabb \ud558\ub294 \uc0ac\ub78c\ub4e4\ub3c4 \ub9ce\uc774 \uc788\uc8e0. \uc800\ub3c4 \uc774\ub7f0 \uc0ac\ub78c \uc911 \ud558\ub098\uc600\uae30 \ub54c\ubb38\uc5d0 \uc774 \uc6d0\uc778\uc744 \ud55c\ubc88 \uc0dd\uac01\ud574 \ubd24\uc5b4\uc694.\\n\\n<div style={{ display: \\"flex\\", flexDirection: \\"column\\", width: \\"50%\\", margin: \\"50px auto\\" }}>\\n  <img src=\\"/img/@guidline/blog-direction/img2.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ display: \\"flex\\", justifyContent: \\"center\\" }} />\\n</div>\\n\\n\uc81c\uac00 \ucc3e\uc740 \uc6d0\uc778\uc740 \'\uc644\ubcbd\uc8fc\uc758\'\uc5d0 \uc788\ub2e4\uace0 \uc0dd\uac01\ud574\uc694. \uc778\ud130\ub137\uc5d0\ub294 \uc544\uc8fc \uc798 \uc4f0\uc778 \uae00\uc774 \ub9ce\uc774 \uc788\uc5b4\uc694. \uadf8\ub807\ub2e4 \ubcf4\ub2c8 \ubb34\uc758\uc2dd\uc911\uc5d0 \ube14\ub85c\uadf8\ub97c \uc4f4\ub2e4\uba74 \uc774 \uc815\ub3c4 \ud004\ub9ac\ud2f0\ub97c \ubcf4\uc5ec\uc918\uc57c \ud55c\ub2e4\uace0 \uc0dd\uac01\ud558\uac8c \ub418\ub294 \uac83 \uac19\uc544\uc694.\\n\\n\uc608\ub97c \ub4e4\uc5b4 \uc5b4\ub5a4 \uae30\uc220 \ub300\ud574\uc11c \uc124\uba85\ud558\ub294 \uae00\uc744 \uc4f0\ub824\uace0 \ud558\uba74 \uba3c\uc800 \uc5b4\ub5a4 \ub0b4\uc6a9\uc744 \uc5bc\ub9c8\ub098 \ub123\uc744\uc9c0, \uc9c0\uae08 \uc54c\uace0 \uc788\ub294 \ub0b4\uc6a9\uc774 \uc815\ud655\ud55c \ub0b4\uc6a9\uc778\uc9c0, \ube60\ub728\ub9b0 \ub0b4\uc6a9\uc740 \uc5c6\ub294\uc9c0 \ucc3e\uc544\uac00\uba70 \uae30\ud68d\uc774 \uacc4\uc18d \ub2ec\ub77c\uc9c8 \uac70\uc608\uc694. \ubb38\uc81c\ub294 \uc774 \ubd80\ubd84\uc5d0 \uc788\ub2e4\uace0 \uc0dd\uac01\ud574\uc694. \ubb3c\ub860 \uc77d\ub294 \uc0ac\ub78c\uc744 \uc704\ud574 \uc591\uc9c8\uc758 \ub0b4\uc6a9\uc744 \uad6c\ud558\ub294 \uac83\uc740 \uc911\uc694\ud574\uc694! \ud558\uc9c0\ub9cc \uc774\ub807\uac8c \uc5d0\ub108\uc9c0\ub97c \ub0ad\ube44\ud558\uace0 \ub098\uba74 \ubc8c\uc368 \uae00\uc744 \uc4f0\uae30 \uc804\ubd80\ud130 \uc9c0\uce58\uac8c \ub418\uc5b4\uc694.\\n\\n<div style={{ display: \\"flex\\", flexDirection: \\"column\\", width: \\"50%\\", margin: \\"50px auto\\" }}>\\n  <img src=\\"/img/@guidline/blog-direction/img3.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ display: \\"flex\\", justifyContent: \\"center\\" }} />\\n</div>\\n\\n\uc6b0\ub9ac\uc758 \ubaa9\uc801\uc740 \uae00\uc744 \uc368\ubcf4\ub294 \uac83\uc5d0 \uc788\uc5b4\uc694. \ube14\ub85c\uadf8\ub97c \uc2dc\uc791\ud558\ub824\uace0 \ub9c9 \ub9c8\uc74c \uba39\uc740 \uc0ac\ub78c\uc758 \uae00\uc744 \ubcf4\uace0 \uc798 \uc37c\ub124, \ud2c0\ub838\ub124, \ud3c9\uac00\ud558\ub294 \uc0ac\ub78c\uc740 \uc5c6\uc5b4\uc694. \uc5b4\ub5a4 \uae00\uc744 \uc4f0\ub354\ub77c\ub3c4 \ubb38\uc81c\uac00 \uc5c6\ub2e4\ub294 \ub9d0\uc774\uc5d0\uc694. \uc9e7\uc544\ub3c4 \ub418\uace0, \ud2c0\ub824\ub3c4 \ub418\uc5b4\uc694. \uc624\ud788\ub824 \uc815\ud655\ud558\uace0 \uc7a5\ud669\ud55c \uae00\uc744 \uc4f0\uae30 \uc704\ud574\uc11c \ud544\uc694 \uc774\uc0c1\uc758 \ub9ce\uc740 \uc5d0\ub108\uc9c0\ub97c \uc4f0\ub294 \uac83\uc744 \ud53c\ud574\uc57c \ud574\uc694. \uae00\uc744 \uc4f8 \ub54c\ub9c8\ub2e4 \uc9c0\uce58\ub294 \uacbd\ud5d8\uc774 \ubc18\ubcf5\ub418\uba74 \ubd84\uba85 \uc624\ub7ab\ub3d9\uc548 \uafb8\uc900\ud788 \uae00\uc744 \uc4f0\uace0 \uc2f6\uc740 \ub9c8\uc74c\uc774 \uc0ac\ub77c\uc9c8 \uac70\uc608\uc694.\\n\\n<div style={{ display: \\"flex\\", flexDirection: \\"column\\", width: \\"50%\\", margin: \\"50px auto\\" }}>\\n  <img src=\\"/img/@guidline/blog-direction/img4.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ display: \\"flex\\", justifyContent: \\"center\\" }} />\\n</div>\\n\\n\ub9c8\uc9c0\ub9c9\uc73c\ub85c BCSDLab \ube14\ub85c\uadf8\uc758 \ucd94\uad6c\ud558\ub294 \ubc29\ud5a5\uc131\uc744 \uc694\uc57d\ud574 \ub4dc\ub9b4\uac8c\uc694.\\n<div style={{  fontSize: \\"18px\\",fontWeight: \\"600\\"}}>\\n  <ol>\\n    <li>\ud615\uc2dd\uc5d0 \uad6c\uc560 \ubc1b\uc9c0 \uc54a\ub294\ub2e4. \uc9e7\uc544\ub3c4 \uc88b\ub2e4.</li>\\n    <li>\uc6d0\ud558\ub294 \uc8fc\uc81c\uc5d0 \uc6d0\ud558\ub294 \uae00\uc744 \uc4f4\ub2e4.</li>\\n    <li>\uc815\ud655\ud558\uc9c0 \uc54a\uc544\ub3c4 \uad1c\ucc2e\ub2e4.</li>\\n    <li>\uacf5\uac10\uacfc \ud53c\ub4dc\ubc31\uc740 O, \ube44\ud310\uc740 X</li>\\n  </ol>\\n</div>\\n\\n\ubaa8\ub4e0 \uc0ac\ub78c\uc774 \ucc98\uc74c\ubd80\ud130 \uc798 \ud560 \uc218 \uc788\ub294 \uac83\uc740 \uc544\ub2c8\uc5d0\uc694. \uc774 \uae00\ub3c4 \ub9c8\ucc2c\uac00\uc9c0\uc774\uace0\uc694. \uc800\ud76c\uac00 \uc6d0\ud558\ub294 \uac83\uc740 \ub204\uad6c\ub098 \uc790\uc720\ub86d\uac8c \uae00\uc744 \uc801\uc744 \uc218 \uc788\ub294 \uacf5\uac04\uc744 \ub9cc\ub4dc\ub294 \uac70\uc608\uc694.\\n\\n\ube14\ub85c\uae45\uc5d0 \uad00\uc2ec\uc774 \uc788\uc9c0\ub9cc \ubd80\ub2f4\uc744 \uac16\uace0 \uc788\uac70\ub098 \ub9c9\ub9c9\ud558\uc2e0 \ubd84\ub4e4\uc774 \uc624\uc154\uc11c \uc774\uac83 \uc800\uac83 \uc2dc\ub3c4\ud574\ubcf4\uace0 \uadf8 \uacbd\ud5d8\uc744 \ud568\uaed8 \ub098\ub20c \uc218 \uc788\uc73c\uba74 \uc88b\uaca0\uc5b4\uc694!"},{"id":"/template","metadata":{"permalink":"/guideline/template","source":"@site/@guideline/template.mdx","title":"\ud15c\ud50c\ub9bf \uc0ac\uc6a9 \uac00\uc774\ub4dc","description":"\ube60\ub974\uac8c \ud15c\ud50c\ub9bf\uc744 \uc0ac\uc6a9\ud574\uc11c \ube14\ub85c\uadf8 \uae00\uc744 \uc791\uc131\ud574 \ubd05\uc2dc\ub2e4!","date":"2024-03-09T00:00:00.000Z","tags":[{"label":"\uac00\uc774\ub4dc","permalink":"/guideline/tags/\uac00\uc774\ub4dc"},{"label":"\ud15c\ud50c\ub9bf","permalink":"/guideline/tags/\ud15c\ud50c\ub9bf"}],"readingTime":6.635,"hasTruncateMarker":true,"authors":[{"name":"minjae Kim","url":"https://github.com/d0dam","email":"smallkdb@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/51052049?v=4","key":"d0dam"}],"frontMatter":{"date":"2024-03-09T00:00:00.000Z","authors":"d0dam","title":"\ud15c\ud50c\ub9bf \uc0ac\uc6a9 \uac00\uc774\ub4dc","description":"\ube60\ub974\uac8c \ud15c\ud50c\ub9bf\uc744 \uc0ac\uc6a9\ud574\uc11c \ube14\ub85c\uadf8 \uae00\uc744 \uc791\uc131\ud574 \ubd05\uc2dc\ub2e4!","keywords":["\uac00\uc774\ub4dc","\ud15c\ud50c\ub9bf"],"tags":["\uac00\uc774\ub4dc","\ud15c\ud50c\ub9bf"]},"unlisted":false,"prevItem":{"title":"BCSD \ube14\ub85c\uadf8\uc758 \ubc29\ud5a5\uc131","permalink":"/guideline/blog-direction"}},"content":"\ube60\ub974\uac8c \ud15c\ud50c\ub9bf\uc744 \uc0ac\uc6a9\ud574\uc11c \ube14\ub85c\uadf8 \uae00\uc744 \uc791\uc131\ud574 \ubd05\uc2dc\ub2e4! [\ubc14\ub85c \ud15c\ud50c\ub9bf \uc4f0\ub7ec \uac00\uae30](/docs/template)\\n\\n{/* truncate */}\\n\\nimport videoUrl from \\"./videos/example.mp4\\";\\nimport ReactPlayer from \\"react-player\\";\\n\\n## \uae00 \ucd5c\uc0c1\ub2e8\uc5d0 \ube14\ub85c\uae45 \uc815\ubcf4 \uc801\uae30\\n\\n```\\n---\\ndate: 2024-03-09 // \uc4f4 \ub0a0\uc9dc\\nauthors: d0dam // \ub0b4 \uad8c\ud55c - author.yml \uc5d0 \uae30\uc7ac\ub418\uc5b4 \uc788\uc2b5\ub2c8\ub2e4.\\ntitle: \\"\ud15c\ud50c\ub9bf \uc0ac\uc6a9 \uac00\uc774\ub4dc\\" // \uc81c\ubaa9\\ndescription: \\"\ube60\ub974\uac8c \ud15c\ud50c\ub9bf\uc744 \uc0ac\uc6a9\ud574\uc11c \ube14\ub85c\uadf8 \uae00\uc744 \uc791\uc131\ud574 \ubd05\uc2dc\ub2e4!\\" // \uc124\uba85\\nkeywords: [\\"\uac00\uc774\ub4dc\\", \\"\ud15c\ud50c\ub9bf\\"] // \ud0a4\uc6cc\ub4dc\\ntags: // \uc0ac\uc6a9\ud560 \ud0dc\uadf8\\n  - \uac00\uc774\ub4dc\\n  - \ud15c\ud50c\ub9bf\\n---\\n\\n\ube14\ub85c\uadf8 \ubbf8\ub9ac\ubcf4\uae30 \uae00 \uc801\uae30\\n\\n{/* truncate */} // \uc774 \uc774\ud6c4\uc5d0\ub294 \ubcf8\ubb38\uc744 \uc801\uc2b5\ub2c8\ub2e4.\\n\\n\ubcf8\ubb38 \uc801\uae30\\n\\n```\\n\\n## \uac04\ub2e8\ud55c \ub9c8\ud06c\ub2e4\uc6b4 \uc0ac\uc6a9\ud574\ubcf4\uae30\\n\\n\uac04\ub2e8\ud55c \ub9c8\ud06c\ub2e4\uc6b4\uc744 \uc54c\uc544\ubd05\uc2dc\ub2e4.\\n\\n```\\n# \uc81c\ubaa91\\n\\n## \uc81c\ubaa92\\n\\n### \uc81c\ubaa93\\n\\n// \ucf54\ub4dc \ubc15\uc2a4\\n`\uac04\ub2e8\ud55c \ub9c8\ud06c\ub2e4\uc6b4 \uc0ac\uc6a9\ud574\ubcf4\uae30`\\n\\n// \uad75\uac8c\\n**\uac04\ub2e8\ud55c \ub9c8\ud06c\ub2e4\uc6b4 \uc0ac\uc6a9\ud574\ubcf4\uae30**\\n\\n// \uae30\uc6b8\uc774\uae30\\n_\uac04\ub2e8\ud55c \ub9c8\ud06c\ub2e4\uc6b4 \uc0ac\uc6a9\ud574\ubcf4\uae30_\\n\\n// \ub9c1\ud06c\\n[\uac04\ub2e8\ud55c \ub9c8\ud06c\ub2e4\uc6b4 \uc0ac\uc6a9\ud574\ubcf4\uae30](\uc5ec\uae30\uc5d0 \ub9c1\ud06c)\\n\\n// \ub9ac\uc2a4\ud305\\n- \uac04\ub2e8\ud55c \ub9c8\ud06c\ub2e4\uc6b4 \uc0ac\uc6a9\ud574\ubcf4\uae30\\n  - 2\\n    - 3\\n\\n// \uac1c\ud589\\n1.\\n\uc548\ub155\ud558\uc138\uc694.\\n\\n\uc548\ub155\ud558\uc138\uc694.\\n\\n2.\\n\uc548\ub155\ud558\uc138\uc694. <br /> \uc548\ub155\ud558\uc138\uc694.\\n```\\n\\n\uc544\ub798\uc640 \uac19\uc774 \ub098\uc635\ub2c8\ub2e4.\\n\\n# \uc81c\ubaa91\\n\\n## \uc81c\ubaa92\\n\\n### \uc81c\ubaa93\\n\\n- \ucf54\ub4dc \ubc15\uc2a4\\n\\n`\uac04\ub2e8\ud55c \ub9c8\ud06c\ub2e4\uc6b4 \uc0ac\uc6a9\ud574\ubcf4\uae30`\\n\\n- \uad75\uac8c\\n\\n**\uac04\ub2e8\ud55c \ub9c8\ud06c\ub2e4\uc6b4 \uc0ac\uc6a9\ud574\ubcf4\uae30**\\n\\n- \uae30\uc6b8\uc774\uae30\\n\\n_\uac04\ub2e8\ud55c \ub9c8\ud06c\ub2e4\uc6b4 \uc0ac\uc6a9\ud574\ubcf4\uae30_\\n\\n- \ub9c1\ud06c\\n\\n[\uac04\ub2e8\ud55c \ub9c8\ud06c\ub2e4\uc6b4 \uc0ac\uc6a9\ud574\ubcf4\uae30](#)\\n\\n- \ub9ac\uc2a4\ud305\\n\\n- \uac04\ub2e8\ud55c \ub9c8\ud06c\ub2e4\uc6b4 \uc0ac\uc6a9\ud574\ubcf4\uae30\\n  - 2\\n    - 3\\n\\n1. \uac1c\ud589 \uccab\ubc88\uc9f8\\n\\n\uc548\ub155\ud558\uc138\uc694.\\n\\n\uc548\ub155\ud558\uc138\uc694.\\n\\n2. \uac1c\ud589 \ub450\ubc88\uc9f8\\n\\n\uc548\ub155\ud558\uc138\uc694. <br /> \uc548\ub155\ud558\uc138\uc694.\\n\\n## \ucf54\ub4dc\ube14\ub7ed \uc0ac\uc6a9\ud558\uae30\\n\\n````\\n```\uc5b8\uc5b4\uba85(ts, js, java, etc) title=\\"\uc81c\ubaa9\\"\\n\\nconst example = \'\uc608\uc2dc\';\\n\\n// highlight-start\\nconst highlight = \'\uc9c4\ud558\uac8c!\';\\n// highlight-end\\n\\n```\\n````\\n\\n\uc774 \ucf54\ub4dc \ube14\ub7ed\uc740 \uc544\ub798\uc640 \uac19\uc774 \ud45c\ud604\ub429\ub2c8\ub2e4.\\n\\n```ts title=\\"\uc81c\ubaa9\\"\\nconst example = \\"\uc608\uc2dc\\";\\n\\n// highlight-start\\nconst highlight = \\"\uc9c4\ud558\uac8c!\\";\\n// highlight-end\\n```\\n\\n## Admonitions \ubc15\uc2a4 \uc0ac\uc6a9\ud558\uae30\\n\\n\ucd1d 4\uac00\uc9c0\uc758 Admonitions \ubc15\uc2a4\ub97c \uc0ac\uc6a9\ud560\uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n```\\n:::note \uc5ec\uae30\uc5d0\ub3c4 \uc81c\ubaa9\uc744 \uc904 \uc218 \uc788\uc5b4\uc694!\\n\\n\uc5ec\uae30\uc5d0\ub3c4 `\ub3d9\uc77c\ud55c` **\ub9c8\ud06c\ub2e4\uc6b4** \ubb38\ubc95\uc744 _\uc801\uc73c\uba74_ \ub429\ub2c8\ub2e4. \uc774\ub807\uac8c [\ub9c1\ud06c\ub85c \uac00\uae30 `click`](#) \ub3c4 \ud560 \uc218 \uc788\uc5b4\uc694.\\n\\n:::\\n\\n:::tip\\n\\n\uc5ec\uae30\uc5d0\ub3c4 `\ub3d9\uc77c\ud55c` **\ub9c8\ud06c\ub2e4\uc6b4** \ubb38\ubc95\uc744 _\uc801\uc73c\uba74_ \ub429\ub2c8\ub2e4. \uc774\ub807\uac8c [\ub9c1\ud06c\ub85c \uac00\uae30 `click`](#) \ub3c4 \ud560 \uc218 \uc788\uc5b4\uc694.\\n\\n:::\\n\\n:::info\\n\\n\uc5ec\uae30\uc5d0\ub3c4 `\ub3d9\uc77c\ud55c` **\ub9c8\ud06c\ub2e4\uc6b4** \ubb38\ubc95\uc744 _\uc801\uc73c\uba74_ \ub429\ub2c8\ub2e4. \uc774\ub807\uac8c [\ub9c1\ud06c\ub85c \uac00\uae30 `click`](#) \ub3c4 \ud560 \uc218 \uc788\uc5b4\uc694.\\n\\n:::\\n\\n:::warning\\n\\n\uc5ec\uae30\uc5d0\ub3c4 `\ub3d9\uc77c\ud55c` **\ub9c8\ud06c\ub2e4\uc6b4** \ubb38\ubc95\uc744 _\uc801\uc73c\uba74_ \ub429\ub2c8\ub2e4. \uc774\ub807\uac8c [\ub9c1\ud06c\ub85c \uac00\uae30 `click`](#) \ub3c4 \ud560 \uc218 \uc788\uc5b4\uc694.\\n\\n:::\\n\\n:::danger\\n\\n\uc5ec\uae30\uc5d0\ub3c4 `\ub3d9\uc77c\ud55c` **\ub9c8\ud06c\ub2e4\uc6b4** \ubb38\ubc95\uc744 _\uc801\uc73c\uba74_ \ub429\ub2c8\ub2e4. \uc774\ub807\uac8c [\ub9c1\ud06c\ub85c \uac00\uae30 `click`](#) \ub3c4 \ud560 \uc218 \uc788\uc5b4\uc694.\\n\\n:::\\n```\\n\\n:::note \uc5ec\uae30\uc5d0\ub3c4 \uc81c\ubaa9\uc744 \uc904 \uc218 \uc788\uc5b4\uc694!\\n\\n\uc5ec\uae30\uc5d0\ub3c4 `\ub3d9\uc77c\ud55c` **\ub9c8\ud06c\ub2e4\uc6b4** \ubb38\ubc95\uc744 _\uc801\uc73c\uba74_ \ub429\ub2c8\ub2e4. \uc774\ub807\uac8c [\ub9c1\ud06c\ub85c \uac00\uae30 `click`](#) \ub3c4 \ud560 \uc218 \uc788\uc5b4\uc694.\\n\\n:::\\n\\n:::tip\\n\\n\uc5ec\uae30\uc5d0\ub3c4 `\ub3d9\uc77c\ud55c` **\ub9c8\ud06c\ub2e4\uc6b4** \ubb38\ubc95\uc744 _\uc801\uc73c\uba74_ \ub429\ub2c8\ub2e4. \uc774\ub807\uac8c [\ub9c1\ud06c\ub85c \uac00\uae30 `click`](#) \ub3c4 \ud560 \uc218 \uc788\uc5b4\uc694.\\n\\n:::\\n\\n:::info\\n\\n\uc5ec\uae30\uc5d0\ub3c4 `\ub3d9\uc77c\ud55c` **\ub9c8\ud06c\ub2e4\uc6b4** \ubb38\ubc95\uc744 _\uc801\uc73c\uba74_ \ub429\ub2c8\ub2e4. \uc774\ub807\uac8c [\ub9c1\ud06c\ub85c \uac00\uae30 `click`](#) \ub3c4 \ud560 \uc218 \uc788\uc5b4\uc694.\\n\\n:::\\n\\n:::warning\\n\\n\uc5ec\uae30\uc5d0\ub3c4 `\ub3d9\uc77c\ud55c` **\ub9c8\ud06c\ub2e4\uc6b4** \ubb38\ubc95\uc744 _\uc801\uc73c\uba74_ \ub429\ub2c8\ub2e4. \uc774\ub807\uac8c [\ub9c1\ud06c\ub85c \uac00\uae30 `click`](#) \ub3c4 \ud560 \uc218 \uc788\uc5b4\uc694.\\n\\n:::\\n\\n:::danger\\n\\n\uc5ec\uae30\uc5d0\ub3c4 `\ub3d9\uc77c\ud55c` **\ub9c8\ud06c\ub2e4\uc6b4** \ubb38\ubc95\uc744 _\uc801\uc73c\uba74_ \ub429\ub2c8\ub2e4. \uc774\ub807\uac8c [\ub9c1\ud06c\ub85c \uac00\uae30 `click`](#) \ub3c4 \ud560 \uc218 \uc788\uc5b4\uc694.\\n\\n:::\\n\\n## \uc0ac\uc9c4 \uc0ac\uc6a9 \uc608\uc2dc\\n\\n\uc0ac\uc9c4\uc744 \uc0ac\uc6a9\ud558\uae30 \uc704\ud574 root\uc758 `/static` \uacbd\ub85c\uc5d0 \uc0ac\uc9c4\uc744 \ub123\uc5b4\uc57c \ud569\ub2c8\ub2e4.\\n\ub123\uc740 \ud6c4 \uc544\ub798\uc640 \uac19\uc774 \uc0ac\uc6a9\ud569\ub2c8\ub2e4.\\n\\n```\\n<img\\n  src=\\"/img/@frontEnd/example.png\\" // static \ud558\uc704\uc758 \uacbd\ub85c\\n  style={{ marginBottom: \\"20px\\" }} // \ub2e4\uc74c \ubb38\uc7a5\uacfc \uc0ac\uc9c4\uacfc\uc758 \uac04\uaca9\uc744 \uc90d\ub2c8\ub2e4.\\n/>\\n```\\n\\n\uc544\ub798\uc640 \uac19\uc774 \uc0ac\uc9c4\uc774 \ub098\uc635\ub2c8\ub2e4.\\n\\n<img src=\\"/img/@frontEnd/example.png\\" style={{ marginBottom: \\"20px\\" }} />\\n\\n## \ube44\ub514\uc624 \uc0ac\uc6a9 \uc608\uc2dc\\n\\n\ube44\ub514\uc624\ub97c \uc0ac\uc6a9\ud558\uae30 \uc704\ud574\uc11c\ub294 `{/* truncate */}` \uc55e\uc5d0 \uc0ac\uc6a9\ud560 \ube44\ub514\uc624\ub97c \uba85\uc2dc\ud574 \uc8fc\uc5b4\uc57c \ud569\ub2c8\ub2e4.\\n\ub9e8 \uc717\uae00\uc744 \ubcf4\uc2dc\uba74 `{/* truncate */}` \uc744 \ud655\uc778 \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\ube44\ub514\uc624\ub294 \uc6d0\ud558\ub294 \uacbd\ub85c\uc5d0 \uc800\uc7a5\ud569\ub2c8\ub2e4. \ub418\ub3c4\ub85d\uc774\uba74 \uc4f0\ub294 \uae00\uc5d0 \uac00\uae5d\uac8c \ub450\uac70\ub098 \uac01 \ud2b8\ub799 \ud3f4\ub354\uc5d0 \ub9cc\ub4e4\uc5b4\uc838 \uc788\ub294 video \ud3f4\ub354\ub97c \uc0ac\uc6a9\ud558\ub294 \uac83\uc744 \ucd94\ucc9c\ud569\ub2c8\ub2e4.\\n`import \ube44\ub514\uc624\uc774\ub984 from \\"\uc0c1\ub300\uacbd\ub85c\\"` \ub85c \ubd88\ub7ec\uc62c \uc218 \uc788\uc2b5\ub2c8\ub2e4. `ReactPlayer`\ub3c4 \uac19\uc774 \ubd88\ub7ec\uc635\ub2c8\ub2e4.\\n\\n\uc544\ub798 \uc608\uc2dc\ub97c \ucc38\uace0\ud574 \uc8fc\uc138\uc694.\\n\\n```\\nimport videoUrl from \\"./videos/example.mp4\\";\\nimport ReactPlayer from \\"react-player\\"; // \uc774 \ubb38\uc7a5\uc740 \uc5b4\ub290 \ud30c\uc77c\uc5d0\uc11c\ub098 \ub3d9\uc77c\ud558\uac8c \uc0ac\uc6a9\ud569\ub2c8\ub2e4.\\n```\\n\\n\uc774\uc81c \uac00\uc838\uc640 \ubd05\uc2dc\ub2e4!\\n\\n```\\n<ReactPlayer\\n  controls // \ucee8\ud2b8\ub864 \ubc14\uc758 \ud45c\uc2dc \uc720\ubb34\uc785\ub2c8\ub2e4.\\n  playing // \uc790\ub3d9 \uc7ac\uc0dd \uc5ec\ubd80\uc785\ub2c8\ub2e4.\\n  loop // \ub3d9\uc601\uc0c1\uc774 \ub05d\ub098\ub3c4 \ub2e4\uc2dc \ucc98\uc74c\ubd80\ud130 \uacc4\uc18d \uc7ac\uc0dd\ud560\uc9c0\ub97c \uacb0\uc815\ud569\ub2c8\ub2e4.\\n  url={videoUrl} // \uc704\uc5d0\uc11c \uc791\uc131\ud55c \\"\ube44\ub514\uc624\uc774\ub984\\"\uc744 \ub123\uc2b5\ub2c8\ub2e4.\\n  style={{ marginBottom: \\"20px\\" }} // \ub2e4\uc74c \ubb38\uc7a5\uacfc \ub3d9\uc601\uc0c1 \uac04 \uac04\uaca9\uc744 \uc90d\ub2c8\ub2e4.\\n/>\\n```\\n\\n\uc544\ub798\uc640 \uac19\uc774 \ub3d9\uc601\uc0c1\uc774 \ub098\uc635\ub2c8\ub2e4.\\n\\n<ReactPlayer\\n  controls\\n  playing\\n  loop\\n  url={videoUrl}\\n  style={{ marginBottom: \\"20px\\" }}\\n/>"}]}')}}]);